class Box {
    private Object value;

    public void setValue(Object value) {
        this.value = value;
    }

    public Object getValue() {
        return value;
    }
}

public class Main {
    public static void main(String[] args) {
        Box box = new Box();
        box.setValue("Java");

        String text = (String) box.getValue();
        System.out.println(text);
    }
}

class Box<T> {
    private T value;

    public void setValue(T value) {
        this.value = value;
    }

    public T getValue() {
        return value;
    }
}

public class Main {
    public static void main(String[] args) {
        Box<String> box = new Box<>();
        box.setValue("Java");

        String text = box.getValue();
        System.out.println(text);
    }
}

class Holder<T> {
    private T data;

    public Holder(T data) {
        this.data = data;
    }

    public T getData() {
        return data;
    }
}

